/**
 * @summary Export pay period data as CSV
 */
export const getExportPayPeriodUrl = (
  periodId: number,
  params: ExportPayPeriodParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/pay-periods/${periodId}/export?${stringifiedParams}`
    : `/api/pay-periods/${periodId}/export`;
};

export const exportPayPeriod = async (
  periodId: number,
  params: ExportPayPeriodParams,
  options?: RequestInit,
): Promise<ExportResult> => {
  return customFetch<ExportResult>(getExportPayPeriodUrl(periodId, params), {
    ...options,
    method: "GET",
  });
};

